return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2026-05-19 10:00:55+0000','plural-forms'=>'nplurals=3; plural=(n == 1) ? 0 : ((n >= 2 && n <= 4) ? 1 : 2);','project-id-version'=>'Plugins - WP Mail SMTP by WPForms &#8211; The Most Popular SMTP and Email Log Plugin - Stable (latest release)','language'=>'cs_CZ','messages'=>['Dismiss'=>'Odmítnout','Something went wrong while connecting to SendLayer. Please try again, or contact support and provide the error code.'=>'Při připojování k SendLayer došlo k chybě. Zkuste to prosím znovu, nebo se obraťte na podporu a uveďte kód chyby.','You can customize your From Email by adding your own domain first on the <a href="%1$s" target="_blank" rel="noopener noreferrer">SendLayer dashboard</a>. Check our <a href="%2$s" target="_blank" rel="noopener noreferrer">documentation</a> on how to add a custom domain.'=>'Adresu odesílatele si můžete přizpůsobit tak, že si nejprve přidáte vlastní doménu v <a href="%1$s" target="_blank" rel="noopener noreferrer">řídicím panelu SendLayer</a>. Podívejte se do naší <a href="%2$s" target="_blank" rel="noopener noreferrer">dokumentace</a>, kde najdete návod, jak přidat vlastní doménu.','From Email Address'=>'Z e-mailové adresy','Setup SendLayer'=>'Nastavení SendLayer','You\'re using the default WordPress mailer, which often lands in spam! Switch to <a href="%s" target="_blank" rel="noopener noreferrer">SendLayer</a>, our recommended mailer, and send your <strong>first 200 emails for free with just a few clicks!</strong>'=>'Používáte výchozí poštovní modul WordPressu, jehož zprávy často končí ve složce se spamem! Přejděte na <a href="%s" target="_blank" rel="noopener noreferrer">SendLayer</a>, náš doporučený poštovní modul, a odešlete svých <strong>prvních 200 e-mailů zdarma pouhými několika kliknutími!</strong>','Seems like you don\'t have a mailer setup yet!'=>'Zdá se, že ještě nemáte nastavený e-mailový klient!','SendLayer disconnect failed. The nonce is invalid. Please try